import numpy as np from sklearn.feature_selection import SelectFromModelfrom sklearn.linear_model import LinearRegressionfrom sklearn.metrics import r2_scorefrom population import Populationfrom sklearn.base import clonefrom data_class import Dataimport nsga_functions as nsgaimport matplotlib.pyplot as pltimport benchmark_metrics as bmfrom ML_code import eval_modelimport timefrom pymoo.indicators.hv import HVfrom parameters import COMMON, REPLICA#%%def my_FNSGA(data, model, scorer, params, seed=None, plot=False):    rng = np.random.default_rng(seed)    N = params["population_size"]    T = params["generations"]    p_c = params["crossover_prob"]    p_m = params["mutation_prob"]    tournament_param = params["tournament_param"]    exploration_param = params["exploration_param"]    seeding_prop = params["seeding_prop"]    ones_prop = params["ones_prop"]    ls_param = params["ls_param"]         # get feature importances based on model evaluation     ## note: removed use of SelectFromModel, as we do not actually implement the selection .     model_fit = clone(model)    model_fit.fit(data.X_train, data.y_train)    feat_importance = model_fit.coef_[0]         # generate initial population    pop_t = Population(N)    pop_t.initialize(data.n, feat_importance, seeding_prop, ones_prop, rng)    pop_t.evaluate(data, model, scorer)         # store initial pop in archive (change archiv size param)    archive = Population(N)    archive = nsga.update_archive(pop_t, archive, N)        # amount of individuals for offspring coming from LS vs ES    N_l = round(N * ls_param)    N_e = N - N_l        # iteration history for plotting     last_fig = None    last_ax = None    if plot:         history = []        for t in range(T):        # set ranks/crowding on archive (needed for ND extraction and tournament select)        fronts = nsga.fast_non_dominated_sort(archive)        for front in fronts:            nsga.crowding_distance(front)            # set ranks/crowding on pop_t (needed for tournament select)        fronts_t = nsga.fast_non_dominated_sort(pop_t)        for front in fronts_t:            nsga.crowding_distance(front)                        # extract non-dominated set from archive        nd_set = Population(0)        nd_set.population = [ind for ind in archive.population if ind.rank == 1]                            # get (normalised) feature scores of nondominated solutions (for local search)        A = nd_set.chromosomes        model_scores = nd_set.fitness[:, 0]        denom = A.sum(axis=0)        denom[denom == 0] = 1        feat_scores = (A.T @ -model_scores) / denom        # Evolutionary Selection        evo_pop = nsga.evolutionary_selection(pop_t, p_c, p_m, tournament_param, exploration_param, len(pop_t), N_e, rng)        evo_pop.evaluate(data, model, scorer)                     LS_return = N_l // 4        # Local Search 1 - add        ls1 = nsga.add_local_search(nd_set, feat_scores, LS_return, rng)                # Local Search 2 - remove        ls2 = nsga.remove_local_search(nd_set, feat_scores, LS_return, rng)                # Local Search 3 - merge        ls3 = nsga.merge_local_search(nd_set, LS_return, rng)                # Local Search 4 - add-remove        ls4 = nsga.add_remove_local_search(nd_set, feat_scores, round(N_l - LS_return*3), rng)                ls_pop = Population(N_l)        ls_pop.population = [*ls1.population, *ls2.population, *ls3.population, *ls4.population]         ls_pop.evaluate(data, model, scorer)                if plot:            def _get_fitness(pop):                f = [ind.fitness for ind in pop.population if ind.fitness is not None]                return np.array(f) if f else np.empty((0, 2))            history.append({                'iteration': t + 1,                'evo': _get_fitness(evo_pop),                'ls1': _get_fitness(ls1),                'ls2': _get_fitness(ls2),                'ls3': _get_fitness(ls3),                'ls4': _get_fitness(ls4),            })        # next generation        offspring = Population(N_e + N_l)        offspring.population = [*evo_pop.population,*ls_pop.population]                rng.shuffle(offspring.population)                 #######        # update the archive and next population        archive = nsga.update_archive(offspring, archive, N)        pop_t = nsga.generation_algorithm(            pop_t,            offspring,            N        )        # pop_t = offspring        print(f"Iteration {t+1}/{T} | ND set size: {len(nd_set)}")    # final ND solution set     fronts = nsga.fast_non_dominated_sort(archive)    final_nd = Population(len(fronts[0]))    final_nd.population = fronts[0]        if plot:        for h in history:            fig, ax = plt.subplots(figsize=(7, 5))            for key, label, color, marker in [                ('evo', 'New solutions: Evolutionary Select', 'red',  'o'),                ('ls1', 'New solutions: Local Search: Add',   'orange',   '*'),                ('ls2', 'New solutions: Local Search: Remove',   'green',   '^'),                ('ls3', 'New solutions: Local Search: Merge',   'blue',   's'),                ('ls4', 'New solutions: Local Search: Add-Remove',   'purple', 'd')            ]:                d = h[key]                if len(d) == 0:                    continue                ax.scatter(d[:, 1], -d[:, 0], label=label, alpha=0.6,                           color=color, marker=marker, s=30)            ax.set_xlabel('Number of Features')            ax.set_ylabel('R²')            ax.set_title(f'My FNSGA\nIteration {h["iteration"]} | Seed {seed}')            ax.legend(loc='lower right', fontsize=8)            plt.tight_layout()            if h["iteration"] == T:                last_fig = fig                last_ax = ax            else:                plt.show()    return final_nd, last_fig, last_ax#%% Single Run dataset_id = 464data = Data(dataset_id)seed = 3444model = LinearRegression()scorer = r2_scorestart = time.time()result, fig, ax = my_FNSGA(data, model, scorer, COMMON, seed=None, plot=True)print(f"\nSeed: {seed}")print(f"Runtime: {time.time() - start:.1f}s")print(f"Final ND set size: {len(result)}") ref_point = np.array([1.1, data.n + 1])fitness = np.array([ind.fitness for ind in result.population])hv = HV(ref_point=ref_point)(fitness)print(f"Hypervolume: {hv:.4f}") ax.scatter(fitness[:, 1], -fitness[:, 0],facecolors="none",    edgecolors="black", label = "Final ND Set (from archive)")ax.legend(loc='lower right', fontsize=8)ax.set_title(f'My FNSGA\nFinal Iteration and Pareto Front | Seed {seed}')plt.show()#%% Compile Results Across Seeds (old - needs fixing)from  FNSGA_replica import replica_FNSGAseed_array = np.random.choice(10000, size = 2, replace = False)extreme_1, extreme_2 = bm.compute_pareto_extremes( data, eval_model, model, scorer)algorithms = {"replica": replica_FNSGA, "my": my_FNSGA}params = {"replica": {**COMMON, **REPLICA}, "my": COMMON}results = bm.run_FNSGA_metrics(seed_array, data, model, scorer,                      ref_point, extreme_1, extreme_2,                       algorithms, params)#%% Build Table of Resultsimport pandas as pdtable = {}for r in results:    seeds = f"seed {r['seed']}     "    table[seeds] = {                    "": "my FNSGA  rep FNSGA |",                    "Hypervolume": f"{r['HV_my']:.2f}    {r['HV_replica']:.2f} |",                    "Spread": f"{r['spread_my']:.2f}      {r['spread_replica']:.2f} |",                    "Spacing": f"{r['spacing_my']:.2f}      {r['spacing_replica']:.2f} |",                    "Runtime (s)": f"{r['time_my']:.2f}     {r['time_replica']:.2f} |"}        df = pd.DataFrame(table)with pd.option_context('display.max_rows', None, 'display.max_columns', None):      print(df)#%% #The Wilcoxon signed-rank test tests the null hypothesis that two related #paired samples come from the same distribution. (from scipy.stats documentation)from scipy.stats import wilcoxonprint("Wilcoxon signed-rank test")for metric in ["HV", "spread", "spacing", "time"]:    v0 = [r[f"{metric}_v0"] for r in results]    v1 = [r[f"{metric}_v1"] for r in results]    diff = np.subtract(v0, v1)    res = wilcoxon(diff)    print(f"{metric}: (statistic, p-val) = ({res.statistic:.4f}, {res.pvalue:.8f})")